'use client';

import { useState, useMemo } from 'react';
import ReactMarkdown from 'react-markdown';
import Image from 'next/image';

interface Article {
  id: string;
  title: string;
  slug: string;
  content: string;
  excerpt: string | null;
  coverImage: string;
  calculatorType: string | null;
  createdAt: string;
}

interface ArticleCardProps {
  article: Article;
  onClick: () => void;
}

export function ArticleCard({ article, onClick }: ArticleCardProps) {
  return (
    <article role="button" tabIndex={0} onClick={onClick} onKeyDown={(e) => e.key === 'Enter' && onClick()} className="group cursor-pointer overflow-hidden rounded-xl border border-border/60 bg-card shadow-sm transition-all duration-300 hover:shadow-lg hover:border-emerald-200 hover:-translate-y-1">
      <div className="relative aspect-[16/10] overflow-hidden bg-gradient-to-br from-emerald-100 to-emerald-50">
        {article.coverImage ? (
          <Image src={article.coverImage} alt={article.title} fill className="object-cover group-hover:scale-105 transition-transform duration-500" sizes="(max-width: 640px) 100vw, (max-width: 1024px) 50vw, 33vw" />
        ) : (
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="text-6xl opacity-30">{article.calculatorType === 'calories' ? '🔥' : article.calculatorType === 'bmi' ? '📊' : '📋'}</div>
          </div>
        )}
        <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent" />
        {article.calculatorType && (
          <div className="absolute top-3 left-3 px-3 py-1 rounded-full bg-emerald-600 text-white text-xs font-medium">
            {article.calculatorType === 'calories' ? '🔥 حاسبة السعرات' : '📊 حاسبة BMI'}
          </div>
        )}
      </div>
      <div className="p-5">
        <h2 className="text-lg font-bold text-foreground leading-relaxed mb-2 group-hover:text-emerald-700 transition-colors line-clamp-2">{article.title}</h2>
        {article.excerpt && <p className="text-sm text-muted-foreground leading-7 line-clamp-2">{article.excerpt}</p>}
        <div className="mt-4 flex items-center justify-between text-xs text-muted-foreground">
          <span className="flex items-center gap-1">📅 {new Date(article.createdAt).toLocaleDateString('ar-SA', { year: 'numeric', month: 'long', day: 'numeric' })}</span>
          <span className="text-emerald-600 font-medium text-sm group-hover:translate-x-[-4px] transition-transform inline-flex items-center gap-1">اقرأ المقال ←</span>
        </div>
      </div>
    </article>
  );
}

export function ArticlePage({ article, allArticles, onGoHome, onGoCalculators }: {
  article: Article;
  allArticles: Article[];
  onGoHome: () => void;
  onGoCalculators: () => void;
}) {
  const [expanded, setExpanded] = useState(false);
  const showCta = expanded;

  const { initialContent, remainingContent } = useMemo(() => {
    const lines = article.content.split('\n');
    const mid = Math.floor(lines.length * 0.4);
    return { initialContent: lines.slice(0, mid).join('\n'), remainingContent: lines.slice(mid).join('\n') };
  }, [article.content]);

  // Related articles (same calculator type, exclude current)
  const related = useMemo(() => {
    return allArticles.filter((a) => a.id !== article.id).slice(0, 3);
  }, [allArticles, article.id]);

  const handleReadMore = () => { setExpanded(true); triggerMonetag(); };

  // Share functions
  const siteUrl = typeof window !== 'undefined' ? window.location.origin : '';
  const articleUrl = `${siteUrl}/articles/${article.slug}`;
  const shareText = `${article.title} — صِحتي`;

  const shareWhatsApp = () => { window.open(`https://wa.me/?text=${encodeURIComponent(shareText + '\n' + articleUrl)}`, '_blank'); };
  const shareTwitter = () => { window.open(`https://twitter.com/intent/tweet?text=${encodeURIComponent(shareText)}&url=${encodeURIComponent(articleUrl)}`, '_blank'); };
  const shareFacebook = () => { window.open(`https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(articleUrl)}`, '_blank'); };
  const copyLink = () => {
    navigator.clipboard.writeText(articleUrl);
    if (typeof window !== 'undefined') { (window as unknown as { toast?: (msg: string) => void }).toast = undefined; }
  };

  return (
    <article className="page-transition">
      {/* Breadcrumb */}
      <nav className="mx-auto max-w-3xl px-4 pt-4 sm:px-6" aria-label="التنقل">
        <ol className="flex items-center gap-2 text-sm text-muted-foreground">
          <li><button onClick={onGoHome} className="hover:text-emerald-600 transition-colors">الرئيسية</button></li>
          <li><span className="text-border">/</span></li>
          <li className="text-foreground font-medium truncate max-w-[200px]">{article.title}</li>
        </ol>
      </nav>

      {/* Hero */}
      <div className="relative aspect-[21/9] sm:aspect-[21/7] overflow-hidden bg-gradient-to-br from-emerald-100 via-emerald-50 to-teal-50">
        {article.coverImage ? (
          <Image src={article.coverImage} alt={article.title} fill className="object-cover" sizes="100vw" priority />
        ) : (
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="text-8xl sm:text-9xl opacity-20">{article.calculatorType === 'calories' ? '🔥' : article.calculatorType === 'bmi' ? '📊' : '📋'}</div>
          </div>
        )}
        <div className="absolute inset-0 bg-gradient-to-t from-background via-background/40 to-transparent" />
        <div className="absolute bottom-0 right-0 left-0 p-6 sm:p-10">
          <h1 className="text-2xl sm:text-3xl lg:text-4xl font-bold text-foreground leading-tight max-w-3xl">{article.title}</h1>
          <div className="mt-3 flex flex-wrap items-center gap-3 text-sm text-muted-foreground">
            <span>📅 {new Date(article.createdAt).toLocaleDateString('ar-SA', { year: 'numeric', month: 'long', day: 'numeric' })}</span>
            {article.calculatorType && (
              <span className="px-2 py-0.5 rounded-full bg-emerald-100 text-emerald-700 text-xs font-medium">
                {article.calculatorType === 'calories' ? '🔥 حاسبة السعرات' : '📊 حاسبة BMI'}
              </span>
            )}
          </div>
        </div>
      </div>

      {/* Share Buttons */}
      <div className="mx-auto max-w-3xl px-4 py-4 sm:px-6">
        <div className="flex items-center gap-2">
