        )}
        {expanded && (
          <>
            <div className="article-content mt-2"><ReactMarkdown>{remainingContent}</ReactMarkdown></div>
            {/* CTA */}
            {showCta && article.calculatorType && (
              <div className="mt-10 rounded-2xl bg-gradient-to-l from-emerald-600 to-emerald-500 p-8 text-center shadow-lg">
                <div className="text-4xl mb-4">{article.calculatorType === 'calories' ? '🔥' : '📊'}</div>
                <h2 className="text-xl sm:text-2xl font-bold text-white mb-3">{article.calculatorType === 'calories' ? '🔥 احسب احتياجك من السعرات الآن' : '📊 احسب مؤشر كتلة جسمك الآن'}</h2>
                <p className="text-emerald-100 mb-6 text-sm sm:text-base">اكتشف احتياجك اليومي واحصل على خطة غذائية مجانية</p>
                <button onClick={onGoCalculators} className="inline-flex items-center gap-2 rounded-xl bg-white px-8 py-3 font-bold text-emerald-700 shadow-md hover:shadow-lg transition-all hover:-translate-y-0.5">ابدأ الحساب الآن ←</button>
              </div>
            )}
            {showCta && !article.calculatorType && (
              <div className="mt-10 rounded-2xl bg-gradient-to-l from-emerald-600 to-teal-500 p-8 text-center shadow-lg">
                <div className="text-4xl mb-4">🧮</div>
                <h2 className="text-xl sm:text-2xl font-bold text-white mb-3">🔥 جرب حاسباتنا الصحية</h2>
                <p className="text-emerald-100 mb-6 text-sm sm:text-base">حاسبات السعرات و BMI والماء والوزن المثالي — مجانًا</p>
                <button onClick={onGoCalculators} className="inline-flex items-center gap-2 rounded-xl bg-white px-8 py-3 font-bold text-emerald-700 shadow-md hover:shadow-lg transition-all hover:-translate-y-0.5">اذهب للحاسبات ←</button>
              </div>
            )}

            {/* Related Articles */}
            {related.length > 0 && (
              <div className="mt-12 border-t border-border pt-8">
                <h2 className="text-xl font-bold text-foreground mb-6">📚 مقالات ذات صلة</h2>
                <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
                  {related.map((a) => (
                    <button key={a.id} onClick={() => onGoHome()} className="group text-right rounded-xl border border-border/60 p-4 hover:shadow-md hover:border-emerald-200 transition-all">
                      <div className="aspect-[16/8] rounded-lg overflow-hidden bg-gradient-to-br from-emerald-50 to-teal-50 mb-3 relative">
                        {a.coverImage && <Image src={a.coverImage} alt={a.title} fill className="object-cover" sizes="200px" />}
                      </div>
                      <h3 className="text-sm font-semibold text-foreground group-hover:text-emerald-700 transition-colors line-clamp-2">{a.title}</h3>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </>
        )}
      </div>
    </article>
  );
}

function triggerMonetag() {
  if (typeof window === 'undefined') return;
  const s = process.env.NEXT_PUBLIC_MONETAG_SRC;
  const z = process.env.NEXT_PUBLIC_MONETAG_ZONE;
  if (!s || !z) return;
  if (sessionStorage.getItem('monetag_loaded')) return;
  sessionStorage.setItem('monetag_loaded', 'true');
  try { const script = document.createElement('script'); script.src = s; script.async = true; script.setAttribute('data-zone', z); document.body.appendChild(script); } catch (err) { console.warn('Monetag failed:', err); }
}

