'use client';

import { useState, useCallback } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { toast } from 'sonner';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, LineChart, Line } from 'recharts';

// ===== Types =====
interface CalorieResult { tdee: number; lose: number; maintain: number; gain: number; }
interface BMIResult { bmi: number; category: string; color: string; }
interface WaterResult { liters: number; cups: number; }
interface IdealWeightResult { min: number; max: number; ideal: number; }
interface DayEntry { date: string; calories: number; goal: number; }

// ===== Main Page =====
export function CalculatorsPage() {
  return (
    <div className="page-transition mx-auto max-w-3xl px-4 py-8 sm:px-6">
      <div className="text-center mb-8">
        <h1 className="text-3xl sm:text-4xl font-bold text-foreground mb-3">🧮 حاسباتك الصحية</h1>
        <p className="text-muted-foreground max-w-lg mx-auto">أدوات تفاعلية لمساعدتك في فهم احتياجاتك الصحية وتحقيق أهدافك</p>
      </div>
      <Tabs defaultValue="calories" className="w-full" dir="rtl">
        <TabsList className="grid w-full grid-cols-2 sm:grid-cols-5 mb-6 h-auto gap-1">
          <TabsTrigger value="calories" className="text-xs sm:text-sm py-2">🔥 السعرات</TabsTrigger>
          <TabsTrigger value="bmi" className="text-xs sm:text-sm py-2">📊 BMI</TabsTrigger>
          <TabsTrigger value="water" className="text-xs sm:text-sm py-2">💧 الماء</TabsTrigger>
          <TabsTrigger value="ideal" className="text-xs sm:text-sm py-2">⚖️ الوزن</TabsTrigger>
          <TabsTrigger value="tracker" className="text-xs sm:text-sm py-2">📊 المتتبع</TabsTrigger>
        </TabsList>
        <TabsContent value="calories"><CalorieCalculator /></TabsContent>
        <TabsContent value="bmi"><BMICalculator /></TabsContent>
        <TabsContent value="water"><WaterCalculator /></TabsContent>
        <TabsContent value="ideal"><IdealWeightCalculator /></TabsContent>
        <TabsContent value="tracker"><DailyTracker /></TabsContent>
      </Tabs>
    </div>
  );
}

// ===== Shared Components =====
function ResultCard({ title, value, unit, color }: { title: string; value: string | number; unit?: string; color?: string }) {
  return (
    <div className="rounded-lg bg-white p-4 text-center border border-emerald-100">
      <div className={`text-2xl font-bold ${color ?? 'text-emerald-600'}`}>{value}</div>
      <div className="text-sm text-muted-foreground mt-1">{title}{unit ? ` (${unit})` : ''}</div>
    </div>
  );
}

function LeadCapture({ type, value }: { type: 'calories' | 'bmi' | 'water' | 'ideal'; value: number }) {
  const [email, setEmail] = useState('');
  const [sent, setSent] = useState(false);
  const [sending, setSending] = useState(false);

  const send = async () => {
    if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) { toast.error('يرجى إدخال بريد إلكتروني صالح'); return; }
    setSending(true);
    try {
      const body: Record<string, string | number> = { email };
      if (type === 'calories') body.calories = value;
      else if (type === 'bmi') body.bmi = value;
      else if (type === 'water') body.goal = `${value} لتر ماء`;
      else body.goal = `${value} كجم`;
      await fetch('/api/leads', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) });
      await fetch('/api/email', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) });
      setSent(true); toast.success('تم الإرسال بنجاح!');
    } catch { toast.error('حدث خطأ أثناء الإرسال'); } finally { setSending(false); }
  };

  if (sent) return (
    <div className="rounded-xl bg-emerald-50 border border-emerald-200 p-5 text-center">
      <div className="text-2xl mb-1">✅</div><h3 className="font-bold text-emerald-800">تم الإرسال بنجاح!</h3>
      <p className="text-sm text-emerald-600 mt-1">تحقق من بريدك الإلكتروني</p>
    </div>
  );

  const label = type === 'calories' ? 'خطة غذائية' : type === 'bmi' ? 'خطة صحية' : type === 'water' ? 'جدول شرب الماء' : 'نصائح لتحقيق الوزن المثالي';

  return (
    <div className="rounded-xl bg-gradient-to-l from-emerald-600 to-teal-500 p-6 text-center text-white">
      <h3 className="text-lg font-bold mb-2">📧 احصل على {label} مجانية</h3>
      <p className="text-emerald-100 text-sm mb-4">أدخل بريدك الإلكتروني وسنرسل لك {label} مخصصة</p>
      <div className="flex gap-2 max-w-sm mx-auto">
        <Input type="email" placeholder="بريدك الإلكتروني" value={email} onChange={(e) => setEmail(e.target.value)} className="bg-white/90 border-0 text-foreground placeholder:text-muted-foreground" dir="ltr" />
        <Button onClick={send} disabled={sending} className="bg-white text-emerald-700 hover:bg-emerald-50 font-semibold shrink-0">{sending ? '⏳' : 'إرسال'}</Button>
      </div>
    </div>
  );
}

// ===== Calorie Calculator =====
function CalorieCalculator() {
  const [age, setAge] = useState('');
  const [gender, setGender] = useState('');
  const [weight, setWeight] = useState('');
  const [height, setHeight] = useState('');
  const [activity, setActivity] = useState('');
  const [result, setResult] = useState<CalorieResult | null>(null);

  const calculate = () => {
    if (!age || !gender || !weight || !height || !activity) { toast.error('يرجى ملء جميع الحقول'); return; }
    const a = Number(age), w = Number(weight), h = Number(height), af = Number(activity);
    if (a < 10 || a > 100) { toast.error('يرجى إدخال عمر صالح'); return; }
    if (w < 20 || w > 300) { toast.error('يرجى إدخال وزن صالح'); return; }
    if (h < 100 || h > 250) { toast.error('يرجى إدخال طول صالح'); return; }
    const bmr = gender === 'male' ? 10 * w + 6.25 * h - 5 * a + 5 : 10 * w + 6.25 * h - 5 * a - 161;
    const tdee = Math.round(bmr * af);
    setResult({ tdee, lose: Math.round(tdee * 0.8), maintain: tdee, gain: Math.round(tdee * 1.2) });
    triggerMonetag();
  };

  return (
    <Card className="border-border/60">
      <CardHeader>
        <CardTitle className="text-xl flex items-center gap-2">🔥 حاسبة السعرات الحرارية</CardTitle>
        <CardDescription>احسب احتياجك اليومي باستخدام معادلة Mifflin-St Jeor</CardDescription>
      </CardHeader>
      <CardContent className="space-y-6">
        <div className="grid gap-4 sm:grid-cols-2">
          <div className="space-y-2"><Label htmlFor="age">العمر (سنوات)</Label><Input id="age" type="number" placeholder="25" value={age} onChange={(e) => setAge(e.target.value)} /></div>
          <div className="space-y-2"><Label>الجنس</Label><Select value={gender} onValueChange={setGender}><SelectTrigger><SelectValue placeholder="اختر الجنس" /></SelectTrigger><SelectContent><SelectItem value="male">ذكر</SelectItem><SelectItem value="female">أنثى</SelectItem></SelectContent></Select></div>
          <div className="space-y-2"><Label htmlFor="weight">الوزن (كجم)</Label><Input id="weight" type="number" placeholder="70" value={weight} onChange={(e) => setWeight(e.target.value)} /></div>
          <div className="space-y-2"><Label htmlFor="height">الطول (سم)</Label><Input id="height" type="number" placeholder="170" value={height} onChange={(e) => setHeight(e.target.value)} /></div>
          <div className="space-y-2 sm:col-span-2"><Label>مستوى النشاط</Label><Select value={activity} onValueChange={setActivity}><SelectTrigger><SelectValue placeholder="اختر مستوى نشاطك" /></SelectTrigger><SelectContent><SelectItem value="1.2">خامل</SelectItem><SelectItem value="1.375">خفيف (1-3 مرات/أسبوع)</SelectItem><SelectItem value="1.55">معتدل (3-5 مرات/أسبوع)</SelectItem><SelectItem value="1.725">نشط (6-7 مرات/أسبوع)</SelectItem><SelectItem value="1.9">نشط جدًا</SelectItem></SelectContent></Select></div>
        </div>
        <Button onClick={calculate} className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-semibold h-12 text-base">احسب احتياجي من السعرات</Button>
        {result && (
          <div className="page-transition space-y-4 pt-2">
            <div className="rounded-xl bg-emerald-50 border border-emerald-200 p-6">
              <h3 className="text-lg font-bold text-emerald-800 mb-4 text-center">نتائجك الشخصية</h3>
              <div className="grid gap-3 sm:grid-cols-3">
                <ResultCard title="لإنقاص الوزن" value={result.lose} unit="سعرة" color="text-red-600" />
                <div className="rounded-lg bg-white p-4 text-center border border-emerald-100 shadow-md ring-2 ring-emerald-300"><div className="text-2xl font-bold text-emerald-600">{result.maintain}</div><div className="text-sm text-muted-foreground mt-1">للحفاظ (سعرة)</div></div>
                <ResultCard title="لزيادة الوزن" value={result.gain} unit="سعرة" color="text-amber-600" />
              </div>
            </div>
            <div className="rounded-xl bg-amber-50 border border-amber-200 p-5">
              <h4 className="font-semibold text-amber-800 mb-2">💡 ماذا تعني هذه الأرقام؟</h4>
              <ul className="text-sm text-amber-700 space-y-1.5 list-disc list-inside">
                <li><strong>إنقاص الوزن</strong>: تناول هذا العدد لتخسر 0.5 كجم أسبوعيًا</li>
                <li><strong>الحفاظ</strong>: احتياجك اليومي للثبات على وزنك</li>
                <li><strong>زيادة الوزن</strong>: لزيادة كتلتك العضلية</li>
              </ul>
            </div>
            <LeadCapture type="calories" value={result.maintain} />
          </div>
        )}
      </CardContent>
    </Card>
  );
}

// ===== BMI Calculator =====
function BMICalculator() {
  const [weight, setWeight] = useState('');
  const [height, setHeight] = useState('');
  const [result, setResult] = useState<BMIResult | null>(null);

  const calculate = () => {
    if (!weight || !height) { toast.error('يرجى ملء جميع الحقول'); return; }
    const w = Number(weight), h = Number(height);
    if (w < 20 || w > 300 || h < 100 || h > 250) { toast.error('يرجى إدخال قيم صالحة'); return; }
    const hm = h / 100, bmi = w / (hm * hm), bmiR = Math.round(bmi * 10) / 10;
    let cat: string, col: string;
    if (bmi < 18.5) { cat = 'نقص في الوزن'; col = 'text-blue-600'; }
    else if (bmi < 25) { cat = 'وزن طبيعي'; col = 'text-emerald-600'; }
    else if (bmi < 30) { cat = 'زيادة في الوزن'; col = 'text-amber-600'; }
    else { cat = 'سمنة'; col = 'text-red-600'; }
    setResult({ bmi: bmiR, category: cat, color: col });
    triggerMonetag();
  };

  const barW = (bmi: number) => bmi < 10 ? 5 : bmi > 45 ? 95 : ((bmi - 10) / 35) * 90 + 5;

  return (
    <Card className="border-border/60">
      <CardHeader>
        <CardTitle className="text-xl flex items-center gap-2">📊 حاسبة مؤشر كتلة الجسم (BMI)</CardTitle>
        <CardDescription>احسب مؤشر كتلة جسمك لمعرفة ما إذا كان وزنك مناسبًا</CardDescription>
      </CardHeader>
      <CardContent className="space-y-6">
        <div className="grid gap-4 sm:grid-cols-2">
          <div className="space-y-2"><Label htmlFor="bw">الوزن (كجم)</Label><Input id="bw" type="number" placeholder="70" value={weight} onChange={(e) => setWeight(e.target.value)} /></div>
          <div className="space-y-2"><Label htmlFor="bh">الطول (سم)</Label><Input id="bh" type="number" placeholder="170" value={height} onChange={(e) => setHeight(e.target.value)} /></div>
        </div>
        <Button onClick={calculate} className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-semibold h-12 text-base">احسب مؤشر كتلة الجسم</Button>
        {result && (
          <div className="page-transition space-y-4 pt-2">
            <div className="rounded-xl bg-emerald-50 border border-emerald-200 p-6 text-center">
              <div className="text-5xl font-bold text-emerald-700 mb-2">{result.bmi}</div>
              <div className={`text-lg font-semibold ${result.color}`}>{result.category}</div>
              <div className="mt-6 px-4">
                <div className="relative h-3 rounded-full overflow-hidden">
                  <div className="absolute inset-0 flex"><div className="flex-1 bg-blue-300" /><div className="flex-[1.5] bg-emerald-400" /><div className="flex-1 bg-amber-400" /><div className="flex-1 bg-red-400" /></div>
                  <div className="absolute top-1/2 -translate-y-1/2 w-1 h-5 bg-foreground rounded-full shadow-md transition-all duration-500" style={{ right: `${barW(result.bmi)}%` }} />
                </div>
                <div className="flex justify-between text-[10px] text-muted-foreground mt-1"><span>10</span><span>18.5</span><span>25</span><span>30</span><span>45</span></div>
              </div>
            </div>
            <div className="rounded-xl bg-muted/50 border border-border p-4">
              <h4 className="font-semibold text-foreground mb-3 text-sm">📋 الفئات</h4>
              <div className="grid gap-2 text-sm">
                {[['أقل من 18.5', 'نقص في الوزن', 'text-blue-600'], ['18.5 - 24.9', 'طبيعي ✓', 'text-emerald-600'], ['25 - 29.9', 'زيادة في الوزن', 'text-amber-600'], ['30+', 'سمنة', 'text-red-600']].map(([r, l, c]) => (
                  <div key={r} className="flex justify-between items-center"><span className="text-muted-foreground">{r}</span><span className={`${c} font-medium`}>{l}</span></div>
                ))}
              </div>
            </div>
            <LeadCapture type="bmi" value={result.bmi} />
          </div>
        )}
      </CardContent>
    </Card>
  );
}

// ===== Water Calculator =====
function WaterCalculator() {
  const [weight, setWeight] = useState('');
  const [activity, setActivity] = useState('');
  const [result, setResult] = useState<WaterResult | null>(null);

  const calculate = () => {
    if (!weight || !activity) { toast.error('يرجى ملء جميع الحقول'); return; }
    const w = Number(weight);
    if (w < 20 || w > 300) { toast.error('يرجى إدخال وزن صالح'); return; }
    let base = w * 0.033;
    if (activity === 'moderate') base += 0.5;
    else if (activity === 'active') base += 1;
    else if (activity === 'intense') base += 1.5;
    const liters = Math.round(base * 10) / 10;
    setResult({ liters, cups: Math.ceil(liters * 4.2) });
    triggerMonetag();
  };

  return (
    <Card className="border-border/60">
      <CardHeader>
        <CardTitle className="text-xl flex items-center gap-2">💧 حاسبة الماء اليومي</CardTitle>
        <CardDescription>احسب كمية الماء التي يحتاجها جسمك يوميًا</CardDescription>
      </CardHeader>
