// ===== Ideal Weight Calculator =====
function IdealWeightCalculator() {
  const [gender, setGender] = useState('');
  const [height, setHeight] = useState('');
  const [age, setAge] = useState('');
  const [result, setResult] = useState<IdealWeightResult | null>(null);

  const calculate = () => {
    if (!gender || !height || !age) { toast.error('يرجى ملء جميع الحقول'); return; }
    const h = Number(height), a = Number(age);
    if (h < 100 || h > 250) { toast.error('يرجى إدخال طول صالح'); return; }
    // Devine formula
    let base: number;
    if (gender === 'male') base = 50 + 2.3 * ((h / 2.54) - 60);
    else base = 45.5 + 2.3 * ((h / 2.54) - 60);
    // Adjust for age
    if (a > 40) base += (a - 40) * 0.2;
    const ideal = Math.round(base);
    const min = Math.round(base * 0.9);
    const max = Math.round(base * 1.1);
    setResult({ min, max, ideal });
    triggerMonetag();
  };

  return (
    <Card className="border-border/60">
      <CardHeader>
        <CardTitle className="text-xl flex items-center gap-2">⚖️ حاسبة الوزن المثالي</CardTitle>
        <CardDescription>اكتشف الوزن المثالي لطولك وجنسك وعمرك</CardDescription>
      </CardHeader>
      <CardContent className="space-y-6">
        <div className="grid gap-4 sm:grid-cols-3">
          <div className="space-y-2"><Label>الجنس</Label><Select value={gender} onValueChange={setGender}><SelectTrigger><SelectValue placeholder="اختر" /></SelectTrigger><SelectContent><SelectItem value="male">ذكر</SelectItem><SelectItem value="female">أنثى</SelectItem></SelectContent></Select></div>
          <div className="space-y-2"><Label>الطول (سم)</Label><Input type="number" placeholder="170" value={height} onChange={(e) => setHeight(e.target.value)} /></div>
          <div className="space-y-2"><Label>العمر</Label><Input type="number" placeholder="25" value={age} onChange={(e) => setAge(e.target.value)} /></div>
        </div>
        <Button onClick={calculate} className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-semibold h-12 text-base">احسب الوزن المثالي</Button>
        {result && (
          <div className="page-transition space-y-4 pt-2">
            <div className="rounded-xl bg-amber-50 border border-amber-200 p-6 text-center">
              <div className="text-5xl mb-2">⚖️</div>
              <div className="text-4xl font-bold text-amber-600">{result.ideal} <span className="text-xl">كجم</span></div>
              <div className="text-muted-foreground mt-1">الوزن المثالي التقريبي</div>
              <div className="mt-4 grid grid-cols-3 gap-3">
                <div className="rounded-lg bg-white p-3 border border-amber-100"><div className="text-lg font-bold text-amber-500">{result.min}</div><div className="text-xs text-muted-foreground">الحد الأدنى</div></div>
                <div className="rounded-lg bg-white p-3 border-2 border-amber-300 shadow-md"><div className="text-lg font-bold text-amber-600">{result.ideal}</div><div className="text-xs text-muted-foreground">المثالي</div></div>
                <div className="rounded-lg bg-white p-3 border border-amber-100"><div className="text-lg font-bold text-amber-500">{result.max}</div><div className="text-xs text-muted-foreground">الحد الأقصى</div></div>
              </div>
            </div>
            <div className="rounded-xl bg-amber-50 border border-amber-200 p-5">
              <h4 className="font-semibold text-amber-800 mb-2">💡 ملاحظة</h4>
              <p className="text-sm text-amber-700 leading-relaxed">
                الوزن المثالي تقديري مبني على معادلة Devine. العوامل مثل الكتلة العضلية وبنية الجسم تؤثر على الوزن الصحي الفعلي. استشر طبيبك للحصول على تقييم دقيق.
              </p>
            </div>
            <LeadCapture type="ideal" value={result.ideal} />
          </div>
        )}
      </CardContent>
    </Card>
  );
}

// ===== Daily Calorie Tracker =====
function DailyTracker() {
  const [entries, setEntries] = useState<DayEntry[]>(() => {
    if (typeof window === 'undefined') return [];
    try { const saved = localStorage.getItem('calorie_tracker'); return saved ? JSON.parse(saved) : []; } catch { return []; }
  });
  const [todayCal, setTodayCal] = useState('');
  const [todayGoal, setTodayGoal] = useState(() => {
    if (typeof window === 'undefined') return '';
    try { return localStorage.getItem('calorie_goal') || ''; } catch { return ''; }
  });

  const saveEntries = useCallback((newEntries: DayEntry[]) => {
    setEntries(newEntries);
    localStorage.setItem('calorie_tracker', JSON.stringify(newEntries));
  }, []);

  const logToday = () => {
    const cal = Number(todayCal);
    const goal = Number(todayGoal);
    if (!cal) { toast.error('أدخل السعرات'); return; }
    const today = new Date().toISOString().split('T')[0];
    const updated = [...entries.filter((e) => e.date !== today), { date: today, calories: cal, goal: goal || cal }];
    saveEntries(updated);
    if (todayGoal) localStorage.setItem('calorie_goal', todayGoal);
    setTodayCal('');
    toast.success('تم تسجيل السعرات ✅');
  };

  const chartData = entries.slice(-7).map((e) => ({
    name: new Date(e.date).toLocaleDateString('ar-SA', { weekday: 'short' }),
    سعرات: e.calories,
    الهدف: e.goal,
  }));

  return (
    <Card className="border-border/60">
      <CardHeader>
        <CardTitle className="text-xl flex items-center gap-2">📊 متتبع السعرات اليومي</CardTitle>
        <CardDescription>تابع استهلاكك اليومي من السعرات (يُحفظ محليًا)</CardDescription>
      </CardHeader>
      <CardContent className="space-y-6">
        <div className="grid gap-4 sm:grid-cols-2">
          <div className="space-y-2">
            <Label>السعرات المتناولة اليوم</Label>
            <Input type="number" placeholder="1800" value={todayCal} onChange={(e) => setTodayCal(e.target.value)} />
          </div>
          <div className="space-y-2">
            <Label>الهدف اليومي</Label>
            <Input type="number" placeholder="2000" value={todayGoal} onChange={(e) => setTodayGoal(e.target.value)} />
          </div>
        </div>
        <div className="flex gap-2">
          <Button onClick={logToday} className="flex-1 bg-emerald-600 hover:bg-emerald-700 text-white font-semibold">📝 سجّل اليوم</Button>
          <Button variant="outline" onClick={() => { if (confirm('حذف كل البيانات؟')) { saveEntries([]); localStorage.removeItem('calorie_goal'); toast.success('تم الحذف'); } }}>🗑️</Button>
        </div>

        {chartData.length > 0 && (
          <>
            <div className="rounded-xl bg-emerald-50 border border-emerald-200 p-4">
              <h4 className="font-semibold text-emerald-800 mb-3 text-sm">📊 آخر 7 أيام</h4>
              <div className="h-64">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={chartData} layout="vertical">
                    <XAxis type="number" domain={[0, 'auto']} />
                    <YAxis dataKey="name" type="category" width={60} tick={{ fontSize: 12 }} />
                    <Tooltip contentStyle={{ direction: 'rtl', fontFamily: 'Cairo, sans-serif' }} />
                    <Bar dataKey="سعرات" fill="#059669" radius={[0, 4, 4, 0]} />
                    <Bar dataKey="الهدف" fill="#d1fae5" radius={[0, 4, 4, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>

            {/* Trend */}
            {entries.length >= 3 && (
              <div className="rounded-xl bg-muted/50 border border-border p-4">
                <h4 className="font-semibold text-foreground mb-3 text-sm">📈 اتجاه السعرات</h4>
                <div className="h-40">
                  <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={chartData}>
                      <XAxis dataKey="name" tick={{ fontSize: 12 }} />
                      <YAxis domain={[0, 'auto']} />
                      <Tooltip contentStyle={{ direction: 'rtl', fontFamily: 'Cairo, sans-serif' }} />
                      <Line type="monotone" dataKey="سعرات" stroke="#059669" strokeWidth={2} dot={{ fill: '#059669' }} />
                      <Line type="monotone" dataKey="الهدف" stroke="#d1fae5" strokeWidth={2} strokeDasharray="5 5" />
                    </LineChart>
                  </ResponsiveContainer>
                </div>
              </div>
            )}
          </>
        )}

        {entries.length === 0 && (
          <div className="text-center py-8 text-muted-foreground">
            <div className="text-4xl mb-2">📝</div>
            <p className="text-sm">ابدأ بتسجيل سعراتك اليومية لتتبع تقدمك</p>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

// ===== Monetag =====
function triggerMonetag() {
  if (typeof window === 'undefined') return;
  const s = process.env.NEXT_PUBLIC_MONETAG_SRC;
  const z = process.env.NEXT_PUBLIC_MONETAG_ZONE;
  if (!s || !z) return;
  if (sessionStorage.getItem('monetag_loaded')) return;
  sessionStorage.setItem('monetag_loaded', 'true');
  try { const script = document.createElement('script'); script.src = s; script.async = true; script.setAttribute('data-zone', z); document.body.appendChild(script); } catch (err) { console.warn('Monetag failed:', err); }
}

