      setTitle('');
      setSlug('');
      setExcerpt('');
      setContent('');
      setCoverImage('');
      setCalculatorType('');
      onCreated();
    } catch {
      toast.error('حدث خطأ أثناء إنشاء المقال');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
