      headers: {
        'Content-Type': 'application/zip',
        'Content-Disposition': 'attachment; filename="sihatti-project.zip"',
        'Content-Length': String(fileBuffer.length),
      },
    });
  } catch {
    return NextResponse.json({ error: 'File not found' }, { status: 404 });
  }
}
